export default function maxChar(str) {
  if (!str) return '';
  const charCount = {};
  let max = 0;
  let maxChar = '';

  for (const ch of str) {
    charCount[ch] = (charCount[ch] || 0) + 1;
    if (charCount[ch] > max) {
      max = charCount[ch];
      maxChar = ch;
    }
  }

  return maxChar;
}

