export default function maxChar(str) {
  if (!str) return '';
  const freq = [...str].reduce((acc, ch) => {
    acc[ch] = (acc[ch] || 0) + 1;
    return acc;
  }, {});

  let maxChar = '';
  let max = 0;
  for (const [ch, count] of Object.entries(freq)) {
    if (count > max) {
      max = count;
      maxChar = ch;
    }
  }
  return maxChar;
}
